1	// claim-office.ts
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	  Rune: 25,
9	  Moonstone: 25,
10	};
11	
12	const FIRST_INSURANCE_PERCENT = 110;
13	const PROCESSING_FEE = 5;
14	
15	type Item = { type: string; cursed?: boolean };
16	
17	const COMPONENT_TYPES = new Set(["Rune", "Moonstone"]);
18	const BLOCK_OF_3_BASE_PREMIUM = 60;
19	const BLOCK_OF_3_SIZE = 3;
20	const CURSED_SURCHARGE_RATE = 0.5;
21	
22	const isBlockOf3Components = (type: string, count: number): boolean =>
23	  COMPONENT_TYPES.has(type) && count === BLOCK_OF_3_SIZE;
24	
25	const baseForGroup = (type: string, count: number): number =>
26	  isBlockOf3Components(type, count)
27	    ? BLOCK_OF_3_BASE_PREMIUM
28	    : BASE_PREMIUMS[type] * count;
29	
30	const countItemsByType = (items: Item[]): Record<string, number> =>
31	  items.reduce<Record<string, number>>((counts, item) => {
32	    counts[item.type] = (counts[item.type] ?? 0) + 1;
33	    return counts;
34	  }, {});
35	
36	const baseTotalFor = (items: Item[]): number =>
37	  Object.entries(countItemsByType(items))
38	    .reduce((total, [type, count]) => total + baseForGroup(type, count), 0);
39	
40	const cursedSurchargeFor = (item: Item): number =>
41	  item.cursed ? BASE_PREMIUMS[item.type] * CURSED_SURCHARGE_RATE : 0;
42	
43	const itemSurchargesFor = (items: Item[]): number =>
44	  items.reduce((total, item) => total + cursedSurchargeFor(item), 0);
45	
46	const quotePremium = (items: Item[]): number => {
47	  const baseTotal = baseTotalFor(items);
48	  const withFirstInsurance = (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
49	  return Math.ceil(withFirstInsurance + itemSurchargesFor(items) + PROCESSING_FEE);
50	};
51	
52	export function processScenario(scenario: any): unknown {
53	  const [{ items }] = scenario.steps;
54	  return { results: [{ premium: quotePremium(items) }] };
55	}
